@startuml
package Actor {
    actor Observer
}

package Interface {
    interface IObserver {
        Notify()
    }
}

package Database {
    database Subject
}

Subject {
    observerCollection
    RegisterObserver(observer)
    UnregisterObserver(observer)
    NotifyObservers()
}

ConcreteObserverA {
    Notify()
}

ConcreteObserverB {
    Notify()
}

Observer ..> Subject : has
Observer <|-- ConcreteObserverA : implements
Observer <|-- ConcreteObserverB : implements

@enduml
